templates.module_java_api_dev:
  {service}:
    image: {service}
    container_name: {service}
    build:
      context: {module_context}
      dockerfile: {dockerfile_dev}
    ports:
      - "${{{port_env}:-{port_default}}}:${{{port_env}:-{port_default}}}"
    env_file:
      - {secrets_rel}/.env.dev
    environment:
      SPRING_PROFILES_ACTIVE: dev
{credential_env_block}{credential_volumes_block}    networks:
      - {network_key}
    restart: unless-stopped
{resource_limits}    healthcheck:
      test: ["CMD-SHELL", "wget -qO- http://localhost:${{{port_env}:-{port_default}}}{health_path} | grep -q UP || exit 1"]
      interval: {health_interval}
      timeout: 5s
      retries: {health_retries}
      start_period: {health_start}

